import React, { useEffect, useState } from "react";
import API from "../../api/api";
import { useNavigate } from "react-router-dom";

const MyProjects = () => {
  const navigate = useNavigate();
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchProjects = async () => {
    try {
      const res = await API.get("/projects/client");
      setProjects(res.data || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  const getStatusStyle = (status) => {
    if (status === "open") return "bg-green-100 text-green-600";
    if (status === "in-progress") return "bg-yellow-100 text-yellow-600";
    if (status === "completed") return "bg-blue-100 text-blue-600";
    return "bg-gray-100 text-gray-600";
  };

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold">My Projects</h2>
        <button
          onClick={() => navigate("/client/post-project")}
          className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition"
        >
          + Post New Project
        </button>
      </div>

      {loading && <p className="text-gray-500">Loading Projects...</p>}

      {!loading && projects.length === 0 && (
        <div className="bg-white p-10 rounded-xl shadow text-center">
          <p className="text-gray-500 text-lg mb-4">No projects posted yet.</p>
          <button
            onClick={() => navigate("/client/post-project")}
            className="bg-teal-600 text-white px-6 py-2 rounded-lg hover:bg-teal-700 transition"
          >
            Post Your First Project
          </button>
        </div>
      )}

      <div className="space-y-4">
        {projects.map((project) => (
          <div key={project.id} className="bg-white p-6 rounded-xl shadow-sm border hover:shadow-md transition">
            <div className="flex justify-between items-start">
              <div className="flex-1">
                <h3 className="text-lg font-semibold text-gray-800">{project.title}</h3>
                <p className="text-gray-600 mt-1 mb-3">{project.description}</p>
                <div className="flex gap-6 text-sm text-gray-500">
                  <span>Budget: <strong className="text-gray-800">₹{project.budget}</strong></span>
                  {project.deadline && <span>Deadline: {project.deadline?.slice(0, 10)}</span>}
                  <span className="text-teal-600 font-medium">{project.proposalsCount || 0} proposals</span>
                </div>
              </div>
              <div className="flex flex-col items-end gap-3 ml-4">
                <span className={`px-3 py-1 rounded-full text-xs font-semibold capitalize ${getStatusStyle(project.status)}`}>
                  {project.status || "open"}
                </span>
                <button
                  onClick={() => navigate(`/client/projects/${project.id}/proposals`)}
                  className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition text-sm"
                >
                  View Proposals
                </button>
                <button
                  onClick={() => navigate(`/client/projects/${project.id}`)}
                  className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition text-sm"
                >
                  View Su
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default MyProjects;
